sys_variable_value.value:
(function execute(inputs, outputs) {
    var serialNumber = inputs.serial_number;

    var restMessage = new sn_ws.RESTMessageV2();
    restMessage.setEndpoint('https://demoalectriallwfzu131128.service-now.com/api/now/table/x_snc_481_medica_0_medical_device');
    restMessage.setHttpMethod('GET');
    restMessage.setBasicAuth('medtric', 'Servicenow123!');
    restMessage.setQueryParameter('sysparm_limit', '1');
    restMessage.setQueryParameter('device_serial_number', serialNumber);
    restMessage.setRequestHeader('Accept', 'application/json');

    var response = restMessage.execute();
    var responseBody = response.getBody();
    var parsed = JSON.parse(responseBody);

    if (parsed.result && parsed.result.length > 0) {
        var record = parsed.result[0];
        outputs.customer_name = record.customer_name || '';
        outputs.device_name = record.device_name || '';
        outputs.warranty_details = record.warranty_details || '';
        outputs.warranty_expiry_date = record.warranty_expiry_date || '';
        outputs.purchase_date = record.purchase_date || '';
        outputs.device_serial_number = record.device_serial_number || '';
    } else {
        outputs.customer_name = '';
        outputs.device_name = '';
        outputs.warranty_details = '';
        outputs.warranty_expiry_date = '';
        outputs.purchase_date = '';
        outputs.device_serial_number = '';
    }
})(inputs, outputs);
